import { useState } from "react";
import { TreeCanvas } from "../../components/tree/TreeCanvas";
import type { TreeNode } from "../../components/tree/types";
import { GraphToolbar, useGraphFilter, defaultGraphFilter } from "../../components/graph";
import { initialTree } from "./data";
import { treeConfig } from "./config";
import { useFixedTemplateTreeHandlers } from "./handlers";

/**
 * FixedTemplateTree — a fully-typed, self-contained tree with a search / sort /
 * filter toolbar above the canvas.
 *
 * Drop into any page:
 *   <FixedTemplateTree />
 *
 * To plug into a backend, edit the handlers in `./handlers.ts`. To remove the
 * toolbar, delete the `GraphToolbar`/`useGraphFilter` wiring below and set
 * `showToolbar: false` in `./config.ts`.
 */
export function FixedTemplateTree() {
  const [tree, setTree] = useState<TreeNode>(initialTree);
  const [filter, setFilter] = useState(defaultGraphFilter);
  const { handleNodeAdd, handleNodeUpdate, handleNodeRemove, handleNodeMove } = useFixedTemplateTreeHandlers();
  const { tree: filteredTree, matches, stats, allTags } = useGraphFilter(tree, filter);

  return (
    <div className="flex flex-col gap-2">
      <GraphToolbar
        filter={filter}
        onChange={setFilter}
        allTags={allTags}
        matched={stats.matched}
        total={stats.total}
      />
      <TreeCanvas
        config={treeConfig}
        tree={filter.mode === "hide" ? filteredTree : tree}
        onTreeChange={setTree}
        highlightIds={filter.mode === "dim" ? matches : undefined}
        onNodeAdd={handleNodeAdd}
        onNodeUpdate={handleNodeUpdate}
        onNodeRemove={handleNodeRemove}
        onNodeMove={handleNodeMove}
      />
    </div>
  );
}

import type { TreeCanvasConfig } from "../../components/tree/types";

/** Static configuration. All fields are typed and validated. */
export const treeConfig: TreeCanvasConfig = {
  "title": "Automation Template",
  "subtitle": "Trigger → Filter → Action — add only what the template allows",
  "layout": "horizontal",
  "editable": true,
  "draggable": false,
  "connector": "stepped",
  "panZoom": true,
  "background": "blueprint",
  "siblingGap": 24,
  "levelGap": 100,
  "minHeight": 420,
  "allowAdd": true,
  "allowEdit": false,
  "allowDelete": false,
  "allowDrag": false,
  "nodeBlueprints": {
    "filter": {
      "label": "Filter step",
      "description": "Conditional branch — pass/fail logic.",
      "meta": {
        "badge": "FILTER",
        "color": "hsl(38 92% 50%)",
        "allowedChildren": [
          "action",
          "filter"
        ],
        "maxChildren": 3
      }
    },
    "action": {
      "label": "Action",
      "description": "Side effect (email / webhook / DB write).",
      "meta": {
        "badge": "ACTION",
        "color": "hsl(160 84% 39%)",
        "maxChildren": 0
      }
    },
    "notify": {
      "label": "Notify",
      "description": "Push notification or email.",
      "meta": {
        "badge": "NOTIFY",
        "color": "hsl(217 91% 60%)",
        "maxChildren": 0
      }
    }
  }
};

import type { TreeNode } from "../../components/tree/types";

/** Initial tree data. Swap with your own backend fetch when wiring up production. */
export const initialTree: TreeNode = {
  "id": "trigger",
  "label": "On new record",
  "meta": {
    "badge": "TRIGGER",
    "blueprintId": "trigger",
    "color": "hsl(280 80% 60%)",
    "locked": true,
    "allowedChildren": [
      "filter",
      "action"
    ],
    "maxChildren": 4
  },
  "children": [
    {
      "id": "f1",
      "label": "Is premium customer?",
      "meta": {
        "badge": "FILTER",
        "blueprintId": "filter",
        "color": "hsl(38 92% 50%)",
        "locked": true,
        "allowedChildren": [
          "action",
          "notify"
        ],
        "maxChildren": 3
      },
      "children": [
        {
          "id": "a1",
          "label": "Send welcome email",
          "meta": {
            "badge": "ACTION",
            "blueprintId": "action",
            "color": "hsl(160 84% 39%)",
            "locked": true,
            "maxChildren": 0
          }
        }
      ]
    },
    {
      "id": "f2",
      "label": "Has billing address?",
      "meta": {
        "badge": "FILTER",
        "blueprintId": "filter",
        "color": "hsl(38 92% 50%)",
        "locked": true,
        "allowedChildren": [
          "action"
        ],
        "maxChildren": 2
      }
    }
  ]
};

import { useCallback } from "react";
import type {
  TreeNodeAddEvent,
  TreeNodeUpdateEvent,
  TreeNodeRemoveEvent,
  TreeNodeMoveEvent,
} from "../../components/tree/types";

/**
 * One handler per mutation — wire each to your backend.
 */
export function useFixedTemplateTreeHandlers() {
  const handleNodeAdd = useCallback((event: TreeNodeAddEvent) => {
    console.log("[tree] node added", event);
  }, []);

  const handleNodeUpdate = useCallback((event: TreeNodeUpdateEvent) => {
    console.log("[tree] node updated", event);
  }, []);

  const handleNodeRemove = useCallback((event: TreeNodeRemoveEvent) => {
    console.log("[tree] node removed", event);
  }, []);

  const handleNodeMove = useCallback((event: TreeNodeMoveEvent) => {
    console.log("[tree] node moved", event);
  }, []);

  return { handleNodeAdd, handleNodeUpdate, handleNodeRemove, handleNodeMove };
}
